def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            continue
        score = 0
        multiplier = 1.0
        for j in range(1, 7):
            factor = j * utilization
            if factor < 0.3:
                score += np.exp(-factor * 2) * (j ** 0.5)
            elif 0.3 <= factor < 0.7:
                score += np.log(factor + 1) * j
            elif 0.7 <= factor < 1:
                score += (factor ** 2) * (7 - j)
            else:
                score += np.sqrt(factor) * (j ** 2)
            if j % 2 == 0:
                multiplier += 0.05 * j
            else:
                multiplier -= 0.03 * j
        if bin_capacity < item * 1.5:
            multiplier *= 1.7
            if utilization > 0.9:
                score += 5
            else:
                score -= 2
        elif item * 3 <= bin_capacity <= item * 4:
            multiplier *= 1.1
            for k in range(3):
                score += (np.sin(utilization * (k + 1) * np.pi) + 1) * 0.5
        elif bin_capacity > item * 6:
            multiplier *= 0.7
            score -= np.log(bin_capacity - item * 6 + 1)
        if utilization < 0.2:
            for _ in range(2):
                score *= 0.9
        if score < 0:
            score = 0
        priorities[i] = score * multiplier
    return priorities
